// Parse Ollama's JSON reply, guard the story count.
const reply = $input.first().json;
const raw = reply?.message?.content || '{}';
let parsed;
try {
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { stories: [] };
}
let stories = Array.isArray(parsed.stories) ? parsed.stories : [];
// Keep only well-formed rows, cap at 8.
stories = stories
  .filter((s) => s && s.line && s.url)
  .map((s) => ({ line: String(s.line).trim(), source: String(s.source || '').trim(), url: String(s.url).trim() }))
  .slice(0, 8);

const issue = $('Combine + Tag Issue').first().json;
return [{
  json: {
    stories,
    story_count: stories.length,
    held: stories.length < 3,
    issue_number: issue.issue_number,
    date_iso: issue.date_iso,
  },
}];

