// Build the Resend batch payload. One rendered email per subscriber (their own
// unsubscribe token in the footer) + one monitor copy to Manu.
// Resend /emails/batch caps at 100 per call — fine at the free-tier list size.
const guard = $('Parse Ollama + Guard').first().json;
const stories = guard.stories;
const issueNumber = guard.issue_number;
const dateLabel = new Date(guard.date_iso).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
const subs = items.map((i) => i.json).filter((s) => s && s.email && s.token);

const SITE = $env.BRIEF_SITE_URL || 'https://taiyka.com';
const FROM = $env.BRIEF_FROM_EMAIL || 'Le Brief <brief@taiyka.com>';
const subject = 'Le Brief #' + String(issueNumber).padStart(3, '0') + ' — ' + dateLabel;

function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

function render(unsubUrl) {
  const rows = stories.map((s, i) => (
    '<tr><td style="padding:0 0 14px 0;">' +
    '<table role="presentation" width="100%"><tr>' +
    '<td width="26" valign="top" style="font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.14em;color:#00a6ff;padding-top:2px;">' + String(i + 1).padStart(2, '0') + '</td>' +
    '<td style="font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;">' +
    '<a href="' + s.url + '" style="font-size:15px;line-height:1.5;color:#e8f0fe;text-decoration:none;">' + esc(s.line) + '</a>' +
    (s.source ? ' <span style="font-size:11px;color:#8fa3bd;">— ' + esc(s.source) + '</span>' : '') +
    '</td></tr></table></td></tr>'
  )).join('');
  return '<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>' +
    '<body style="margin:0;padding:0;background:#0a1628;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#0a1628;"><tr><td align="center" style="padding:28px 16px;">' +
    '<table role="presentation" width="560" cellpadding="0" cellspacing="0" style="max-width:560px;width:100%;background:#0f1a2e;border:1px solid rgba(141,162,192,0.2);border-radius:8px;padding:26px;">' +
    '<tr><td style="border-bottom:1px solid rgba(141,162,192,0.2);padding-bottom:14px;"><table role="presentation" width="100%"><tr>' +
    '<td style="font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.2em;text-transform:uppercase;color:#00a6ff;">LE BRIEF · #' + String(issueNumber).padStart(3, '0') + '</td>' +
    '<td align="right" style="font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#8fa3bd;">' + dateLabel + ' · 7h</td>' +
    '</tr></table></td></tr>' +
    '<tr><td style="padding:22px 0 0 0;"><table role="presentation" width="100%">' + rows + '</table></td></tr>' +
    '<tr><td style="border-top:1px solid rgba(141,162,192,0.2);padding-top:14px;text-align:center;font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;font-size:12px;color:#8fa3bd;">' +
    '<p style="margin:0 0 6px 0;">— Manu · <a href="https://instagram.com/manu_ai.to" style="color:#00a6ff;text-decoration:none;">@manu_ai.to</a></p>' +
    '<p style="margin:0;font-size:11px;"><a href="' + unsubUrl + '" style="color:#8fa3bd;text-decoration:underline;">Se désinscrire en 1 clic</a></p>' +
    '</td></tr></table></td></tr></table></body></html>';
}

const batch = [];
// Monitor copy to Manu (visibility for the first ~2 weeks; one email/day, not a BCC per recipient).
batch.push({ from: FROM, to: 'manu.uhila@taiyka.com', subject: '[COPIE] ' + subject, html: render(SITE + '/brief') });
for (const s of subs) {
  const unsub = SITE + '/api/brief/unsubscribe?token=' + s.token;
  batch.push({ from: FROM, to: s.email, subject, html: render(unsub) });
}

return [{ json: { batch, sent_count: subs.length, story_count: stories.length } }];
